import React, { useState, useEffect, useMemo } from 'react';
import { useGame } from '../../context/GameContext';
import { Sword, Shield, Zap, Brain, Check, Star, ArrowUp, Award, Sparkles, Lock, Activity, Heart, Wind } from 'lucide-react';
import { getAssetUrl } from '../../utils';
import { EquipmentStats } from '../../models/Equipment';
import { EQUIPMENT_ITEMS } from '../../data/equipment';
import { MASTERY_THRESHOLDS } from '../../config/mastery-config';
import { UI_MODAL_LAYOUT } from '../../config/ui-config';

const CraftingResultModal = () => {
    const { state, actions } = useGame();
    const item = state.lastCraftedItem;
    const [animatedProgress, setAnimatedProgress] = useState(0);

    const masteryInfo = useMemo(() => {
        if (!item || !item.equipmentData || !item.equipmentData.recipeId) return null;

        const recipeId = item.equipmentData.recipeId;
        const count = state.craftingMastery[recipeId] || 0;

        let label = "Novice";
        let colorClass = "stroke-stone-400";
        let textClass = "text-stone-400";
        let progress = 0;

        if (count >= MASTERY_THRESHOLDS.ARTISAN) {
            label = "Artisan";
            colorClass = "stroke-amber-500";
            textClass = "text-amber-500";
            progress = Math.min(100, ((count - MASTERY_THRESHOLDS.ARTISAN) / 20) * 100);
        } else if (count >= MASTERY_THRESHOLDS.ADEPT) {
            label = "Adept";
            colorClass = "stroke-emerald-500";
            textClass = "text-emerald-500";
            progress = ((count - MASTERY_THRESHOLDS.ADEPT) / (MASTERY_THRESHOLDS.ARTISAN - MASTERY_THRESHOLDS.ADEPT)) * 100;
        } else {
            label = "Novice";
            colorClass = "stroke-stone-400";
            textClass = "text-stone-400";
            progress = (count / MASTERY_THRESHOLDS.ADEPT) * 100;
        }

        const radius = 46;
        const circumference = 2 * Math.PI * radius;

        return { label, colorClass, textClass, progress, circumference, count };
    }, [item, state.craftingMastery]);

    useEffect(() => {
        if (masteryInfo) {
            setAnimatedProgress(0);
            const timer = setTimeout(() => {
                setAnimatedProgress(masteryInfo.progress);
            }, 100);
            return () => clearTimeout(timer);
        }
    }, [masteryInfo]);

    if (!item || !item.equipmentData || !masteryInfo) return null;

    const playClick = () => {
        window.dispatchEvent(new CustomEvent('play-sfx', { detail: { file: 'item_click.wav' } }));
    };

    const data = item.equipmentData;
    const recipe = EQUIPMENT_ITEMS.find(r => r.id === data.recipeId);
    const imageUrl = data.image 
        ? getAssetUrl(data.image, 'equipments') 
        : (data.recipeId 
            ? getAssetUrl(`${recipe?.id}.png`, 'equipments') 
            : getAssetUrl(`${item.id.split('_')[0]}.png`, 'equipments'));

    const getQualityLabel = (q: number): string => {
        if (q >= 110) return "Masterwork";
        if (q >= 100) return "Pristine";
        if (q >= 90) return "Superior";
        if (q >= 80) return "Fine";
        if (q >= 70) return "Standard";
        if (q >= 60) return "Rustic";
        return "Crude";
    };

    const getQualityColor = (q: number): string => {
        if (q >= 110) return 'text-amber-400';
        if (q >= 100) return 'text-yellow-400';
        if (q >= 90) return 'text-emerald-400';
        if (q >= 80) return 'text-blue-400';
        return 'text-stone-400';
    };

    const label = getQualityLabel(data.quality);
    const qColor = getQualityColor(data.quality);

    const isLockedByTutorial = state.tutorialStep === 'CRAFT_RESULT_DIALOG';

    const handleFinalize = () => {
        if (isLockedByTutorial) return;
        playClick();
        if (state.tutorialStep === 'FINALIZE_FORGE_GUIDE') {
            actions.setTutorialStep('SHOP_INTRO_DIALOG');
        }
        actions.dismissCraftingResult();
    };

    const renderStatItem = (icon: React.ReactNode, labelStr: string, statKey: keyof EquipmentStats, value: number, customTagClass?: string) => {
        if (value === undefined || value <= 0) return null;

        const baseValue = recipe?.baseStats?.[statKey] || 0;
        const diff = value - baseValue;
        const isUp = diff > 0;

        return (
            <div className={`bg-stone-950/50 p-2 md:p-3 rounded-xl border transition-all flex justify-between items-center ${isUp ? 'border-amber-600/40 shadow-[inner_0_0_10px_rgba(245,158,11,0.1)]' : 'border-stone-800'} ${customTagClass || ''}`}>
                <span className="text-[7px] md:text-[10px] text-stone-500 font-bold uppercase flex items-center gap-1 md:gap-1.5 pr-1 truncate">
                    {icon} {labelStr}
                </span>
                <div className="flex items-center gap-0.5 shrink-0">
                    <span className={`text-[10px] md:text-sm font-mono font-black ${isUp ? 'text-amber-400' : 'text-stone-200'}`}>{value}</span>
                    {isUp && <ArrowUp className="w-2 h-2 md:w-2.5 md:h-2.5 text-amber-500 animate-bounce" />}
                </div>
            </div>
        );
    };

    const offset = masteryInfo.circumference - (animatedProgress / 100) * masteryInfo.circumference;

    return (
        <div className={`${UI_MODAL_LAYOUT.OVERLAY} ${UI_MODAL_LAYOUT.Z_INDEX.RESULT}`}>
            <div className={`${UI_MODAL_LAYOUT.CONTAINER} border-amber-600 animate-in zoom-in-95 duration-300`}>

                <div className="bg-stone-850 p-3 md:p-6 border-b border-stone-800 flex flex-col items-center text-center shrink-0">

                    <div className="relative mb-2 md:mb-4 group">
                        <div className={`w-20 h-20 md:w-32 md:h-32 bg-stone-900 rounded-full flex items-center justify-center relative z-10 p-2 md:p-3 border border-stone-800/50 shadow-2xl`}>
                            <svg className="absolute inset-0 w-full h-full -rotate-90 pointer-events-none scale-105" viewBox="0 0 100 100">
                                <circle cx="50" cy="50" r="46" stroke="currentColor" strokeWidth="4" fill="transparent" className="text-stone-950/40" />
                                <circle 
                                    cx="50" cy="50" r="46" 
                                    stroke="currentColor" strokeWidth="4" fill="transparent"
                                    strokeDasharray={masteryInfo.circumference}
                                    strokeDashoffset={offset}
                                    strokeLinecap="round"
                                    className={`${masteryInfo.colorClass} transition-all duration-[1000ms] ease-out`}
                                />
                            </svg>

                            <img src={imageUrl} className="w-10 h-10 md:w-20 md:h-20 object-contain p-2 md:p-3 drop-shadow-2xl z-20 relative" />

                            <div className={`absolute -bottom-1 -right-1 md:bottom-2 md:right-2 z-30 px-1 md:px-1.5 py-0.5 rounded-full border border-stone-700 bg-stone-900 shadow-xl flex items-center gap-1`}>
                                <Star className={`w-2 h-2 md:w-3 md:h-3 fill-current ${masteryInfo.textClass}`} />
                                <span className={`text-[6px] md:text-[9px] font-black uppercase tracking-tighter ${masteryInfo.textClass}`}>{masteryInfo.label}</span>
                            </div>
                        </div>
                    </div>

                    <h2 className="text-base md:text-2xl font-bold text-stone-100 font-serif leading-tight px-2 truncate w-full">{data.name}</h2>

                    <div className="flex flex-col items-center gap-1 mt-1 md:mt-2">
                        <div className={`px-2 md:px-3 py-0.5 md:py-1 rounded-full bg-stone-950 border border-stone-800 font-black uppercase tracking-widest text-[7px] md:text-[10px] ${qColor} flex items-center gap-1 shadow-inner`}>
                            <Sparkles className="w-2.5 h-2.5 md:w-3.5 md:h-3.5 fill-current" /> {label} Quality
                        </div>
                        <div className="flex items-center gap-1 text-[7px] md:text-[9px] font-black text-stone-500 uppercase tracking-widest">
                            <Award className="w-2 h-2 md:w-2.5 md:h-2.5" /> Mastery: {Math.round(masteryInfo.progress)}%
                        </div>
                    </div>
                </div>

                <div className="p-3 md:p-6 space-y-4 overflow-y-auto flex-1 custom-scrollbar">
                    <p className="text-stone-400 text-[9px] md:text-sm text-center italic leading-tight px-2">"{item.description}"</p>

                    {/* Unified Stats Grid - 2 columns */}
                    <div className="grid grid-cols-2 gap-1.5 md:gap-2">
                        {renderStatItem(<Sword className="w-2.5 h-2.5 text-stone-50" />, "P.Atk", "physicalAttack", data.stats.physicalAttack)}
                        {renderStatItem(<Zap className="w-2.5 h-2.5 text-stone-50" />, "M.Atk", "magicalAttack", data.stats.magicalAttack)}
                        {renderStatItem(<Shield className="w-2.5 h-2.5 text-stone-50" />, "P.Def", "physicalDefense", data.stats.physicalDefense)}
                        {renderStatItem(<Brain className="w-2.5 h-2.5 text-stone-50" />, "M.Def", "magicalDefense", data.stats.magicalDefense)}

                        {/* Bonus Stats in the same grid with color coding */}
                        {renderStatItem(<Activity className="w-2.5 h-2.5 text-orange-400" />, "STR", "str", data.stats.str || 0, "border-orange-500/20 bg-orange-500/10")}
                        {renderStatItem(<Heart className="w-2.5 h-2.5 text-red-400" />, "VIT", "vit", data.stats.vit || 0, "border-red-500/20 bg-red-500/10")}
                        {renderStatItem(<Wind className="w-2.5 h-2.5 text-emerald-400" />, "DEX", "dex", data.stats.dex || 0, "border-emerald-500/20 bg-emerald-500/10")}
                        {renderStatItem(<Brain className="w-2.5 h-2.5 text-blue-400" />, "INT", "int", data.stats.int || 0, "border-blue-500/20 bg-blue-500/10")}
                        {renderStatItem(<Star className="w-2.5 h-2.5 text-pink-400" />, "LUK", "luk", data.stats.luk || 0, "border-pink-500/20 bg-pink-500/10")}
                    </div>
                </div>

                <div className="p-3 md:p-5 border-t border-stone-800 bg-stone-850 shrink-0">
                    <button 
                        onClick={handleFinalize} 
                        disabled={isLockedByTutorial}
                        data-tutorial-id="FINALIZE_BUTTON"
                        className={`w-full py-2.5 md:py-4 font-black rounded-xl shadow-lg flex items-center justify-center gap-2 transition-all text-[10px] md:text-base uppercase tracking-widest border-b-4 ${
                            isLockedByTutorial 
                            ? 'bg-stone-800 text-stone-600 border-stone-900 grayscale cursor-not-allowed' 
                            : 'bg-amber-600 hover:bg-amber-500 text-white border-amber-800 active:scale-95'
                        }`}
                    >
                        {isLockedByTutorial ? (
                            <><Lock className="w-3 h-3 md:w-4 md:h-4" /> Reviewing...</>
                        ) : (
                            <><Check className="w-3 h-3 md:w-4 md:h-4" /> Finalize Forge</>
                        )}
                    </button>
                </div>
            </div>
        </div>
    );
};

export default CraftingResultModal;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { useGame } from '../../../context/GameContext';
import DialogueBox from '../../DialogueBox';
import { ArrowLeft, Heart, Gift, MessageSquare, UserPlus, Package, X, Star, Wrench, Search, UserMinus, Ban, Lock, Unlock, Sword, Shield, ChevronUp } from 'lucide-react';
import { getAssetUrl } from '../../../utils';
import { Mercenary } from '../../../models/Mercenary';
import { CONTRACT_CONFIG, calculateHiringCost } from '../../../config/contract-config';
import { InventoryItem, EquipmentSlotType } from '../../../types/inventory';
import { MercenaryDetailModal } from '../../modals/MercenaryDetailModal';
import { ItemSelectorList } from '../../ItemSelectorList';
import { AnimatedMercenary } from '../../common/ui/AnimatedMercenary';
import { MercenaryPortrait } from '../../common/ui/MercenaryPortrait';

interface TavernInteractionProps {
    mercenary: Mercenary;
    onBack: () => void;
}

interface FloatingHeart {
    id: number;
    left: number;
    delay: number;
    size: number;
}

type InteractionStep = 'IDLE' | 'CONFIRM_HIRE' | 'CONFIRM_FIRE';

const TavernInteraction: React.FC<TavernInteractionProps> = ({ mercenary, onBack }) => {
    const { state, actions } = useGame();
    const [dialogue, setDialogue] = useState(`(You sit across from ${mercenary.name}.)`);
    const [showGiftMenu, setShowGiftMenu] = useState(false);
    const [showDetail, setShowDetail] = useState(false);
    const [pendingGiftItem, setPendingGiftItem] = useState<InventoryItem | null>(null);
    const [floatingHearts, setFloatingHearts] = useState<FloatingHeart[]>([]);
    const [step, setStep] = useState<InteractionStep>('IDLE');
    const isHired = mercenary.status === 'HIRED' || mercenary.status === 'ON_EXPEDITION' || mercenary.status === 'INJURED';
    const isOnExpedition = mercenary.status === 'ON_EXPEDITION';
    const hiringCost = calculateHiringCost(mercenary.level, mercenary.job);
    const canAfford = state.stats.gold >= hiringCost;
    const hasAffinity = mercenary.affinity >= CONTRACT_CONFIG.HIRE_AFFINITY_THRESHOLD;
    const hasUnallocated = isHired && (mercenary.bonusStatPoints || 0) > 0;

    const playClick = useCallback(() => {
        window.dispatchEvent(new CustomEvent('play-sfx', { detail: { file: 'item_click.wav' } }));
    }, []);

    const handleTalk = () => {
        if (pendingGiftItem || step !== 'IDLE') return;
        playClick();

        if (!state.talkedToToday.includes(mercenary.id)) {
            actions.talkMercenary(mercenary.id);
            const newHearts = Array.from({ length: 5 }).map((_, i) => ({
                id: Date.now() + i,
                left: 40 + Math.random() * 20,
                delay: Math.random() * 0.5,
                size: 16 + Math.random() * 12
            }));
            setFloatingHearts(prev => [...prev, ...newHearts]);
            setTimeout(() => setFloatingHearts([]), 3000);
        }

        const lines = [
            "The road is long, but a warm fire makes it easier.",
            "I heard rumors of rare ores in the Rat Cellar...",
            "What's your specialty, smith? I need something that won't break.",
            "Business seems slow today. Maybe I can help with that later.",
            "I've seen many forges, but yours has... potential.",
            "Tell me, do you have any ale left?",
            "I'm looking for work. Something that pays in gold and glory."
        ];
        setDialogue(lines[Math.floor(Math.random() * lines.length)]);
    };

    const handleRecruitInit = () => {
        playClick();
        if (!hasAffinity) {
            setDialogue("I don't know you well enough to pledge my blade to your forge yet.");
            return;
        }
        if (!canAfford) {
            setDialogue(`The contract is ${hiringCost} gold. Come back when you have the coin.`);
            return;
        }
        setStep('CONFIRM_HIRE');
        setDialogue(`"A contract for ${hiringCost} Gold? Are you certain you want me on your squad?"`);
    };

    const handleConfirmHire = () => {
        actions.hireMercenary(mercenary.id, hiringCost);
        setStep('IDLE');
        setDialogue("A fair contract. My strength is yours, Lockhart.");
    };

    const handleTerminateInit = () => {
        playClick();
        setStep('CONFIRM_FIRE');
        setDialogue(`(Surprised) "Terminate the contract? Did I fail you in some way? If you let me go now, I might not return for some time."`);
    };

    const handleConfirmTerminate = () => {
        actions.fireMercenary(mercenary.id);
        setStep('IDLE');
        setDialogue(`"I see. Perhaps our paths will cross again on another road. Farewell, smith."`);
    };

    const handleRecall = () => {
        if (mercenary.assignedExpeditionId) {
            playClick();
            if (window.confirm("Abort current mission and recall the entire squad? No rewards will be gained.")) {
                actions.abortExpedition(mercenary.assignedExpeditionId);
                setDialogue("(Heavy breathing) We're back. The mission was too hazardous... we had to retreat.");
            }
        }
    };

    const handleCancelStep = () => {
        setStep('IDLE');
        setDialogue(`"I'm glad we cleared that up."`);
    };

    const handleSelectItemForGift = (item: InventoryItem) => {
        if (item.isLocked) {
            actions.showToast("Cannot gift locked items.");
            return;
        }
        playClick();
        setPendingGiftItem(item);
        setShowGiftMenu(false);
        const raritySuffix = item.type === 'EQUIPMENT' ? ` (${item.equipmentData?.rarity})` : '';
        setDialogue(`(You hold out the ${item.name}${raritySuffix}.) "Would you like this?"`);
    };

    const handleConfirmGift = () => {
        if (!pendingGiftItem) return;
        const item = pendingGiftItem;
        actions.giveGift(mercenary.id, item.id);

        if (item.type === 'EQUIPMENT' && item.equipmentData) {
            const q = item.equipmentData.quality;
            if (q > 100) {
                setDialogue(`(Eyes widening) "Is this for me? A masterpiece like this? I... I am truly honored, Lockhart. I will carry it with my life."`);
            } else if (q < 80) {
                setDialogue(`"A gift? I appreciate the gesture, but... this ${item.name} looks a bit worse for wear. I hope your anvil finds its true rhythm soon."`);
            } else {
                setDialogue(`(Surprised) "Is this for me? A ${item.name}? I will carry it with honor."`);
            }
        } else {
            setDialogue(`${mercenary.name} seems pleased with the gift. "For me? You're too kind."`);
        }
        setPendingGiftItem(null);
    };

    const handleCancelGift = () => {
        setPendingGiftItem(null);
        setDialogue(`(You pull your hand back.) "Actually, never mind."`);
    };

    const handleShowDetail = () => {
        playClick();
        setShowDetail(true);
    };

    const handleBack = () => {
        playClick();
        onBack();
    };

    // Filter restricted to Mercenary's interests
    const giftableItems = state.inventory.filter(i => 
        ['EQUIPMENT', 'PRODUCT', 'CONSUMABLE', 'GIFT'].includes(i.type)
    );

    return (
        <div className="fixed inset-0 z-[1000] bg-stone-950 overflow-hidden flex flex-col items-center justify-center">

            <style>
                {`
                    @keyframes heartFloatUp {
                        0% { transform: translateY(0) translateX(0) scale(0.5); opacity: 0; }
                        20% { opacity: 1; }
                        100% { transform: translateY(-300px) translateX(var(--wobble)) scale(1.2); opacity: 0; }
                    }
                    .animate-heart {
                        animation: heartFloatUp 2.5s ease-out forwards;
                    }
                `}
            </style>

            <div className="absolute inset-0 z-0">
                <img 
                    src={getAssetUrl('tavern_bg.jpeg', 'bg')} 
                    alt="Tavern Interior" 
                    className="absolute inset-0 w-full h-full object-cover opacity-50"
                />
                <div className="absolute inset-0 bg-black/40"></div>
            </div>

            <button 
                onClick={handleBack}
                className="absolute top-4 left-4 z-[1050] flex items-center gap-2 px-4 py-2 bg-stone-900/80 hover:bg-red-900/60 text-stone-300 hover:text-red-100 rounded-xl border border-stone-700 backdrop-blur-md transition-all shadow-2xl active:scale-90 group"
                title="Leave Interaction"
            >
                <ArrowLeft className="w-4 h-4 group-hover:-translate-x-1 transition-transform" />
                <span className="text-xs font-black uppercase tracking-widest">Back</span>
            </button>

            <div className="absolute top-20 left-4 z-40 animate-in slide-in-from-left-4 duration-500 w-[32%] max-w-[180px] md:max-w-[240px]">
                <div className="bg-stone-900/90 border border-stone-700 p-2.5 md:p-4 rounded-xl backdrop-blur-md shadow-2xl">
                    <div className="flex justify-between items-center mb-1.5 md:mb-2.5">
                        <div className="flex items-center gap-2 min-w-0">
                            <MercenaryPortrait mercenary={mercenary} className="w-7 h-7 md:w-9 md:h-9 rounded-lg border border-white/10 shrink-0" />
                            <div className="flex flex-col leading-tight min-w-0">
                                <span className="font-black text-amber-50 text-[8px] md:text-[10px] tracking-widest uppercase truncate">{mercenary.job}</span>
                                <span className="text-stone-500 text-[8px] md:text-[10px] font-mono">Lv.{mercenary.level}</span>
                            </div>
                        </div>
                        <div className="flex items-center gap-1 text-pink-400 font-bold bg-pink-950/20 px-1 md:px-1.5 py-0.5 rounded border border-pink-900/30 shrink-0">
                            <Heart className="w-2.5 h-2.5 md:w-3.5 md:h-3.5 fill-pink-400" />
                            <span className="font-mono text-[9px] md:text-xs">{mercenary.affinity}</span>
                        </div>
                    </div>

                    <div className="space-y-1.5 md:space-y-2.5">
                        <div className="flex flex-col gap-0.5">
                            <div className="flex justify-between items-center text-[7px] md:text-[9px] font-mono text-stone-500 px-0.5">
                                <span>HP</span>
                                <span>{Math.floor(mercenary.currentHp)}/{mercenary.maxHp}</span>
                            </div>
                            <div className="w-full bg-stone-950 h-1 md:h-1.5 rounded-full overflow-hidden border border-stone-800">
                                <div className="bg-red-600 h-full transition-all duration-700" style={{ width: `${(mercenary.currentHp / mercenary.maxHp) * 100}%` }}></div>
                            </div>
                        </div>
                        <div className="flex flex-col gap-0.5">
                            <div className="flex justify-between items-center text-[7px] md:text-[9px] font-mono text-stone-500 px-0.5">
                                <span>MP</span>
                                <span>{Math.floor(mercenary.currentMp)}/{mercenary.maxMp}</span>
                            </div>
                            <div className="w-full bg-stone-950 h-1 md:h-1.5 rounded-full overflow-hidden border border-stone-800">
                                <div className="bg-blue-600 h-full transition-all duration-700" style={{ width: `${(mercenary.currentMp / mercenary.maxMp) * 100}%` }}></div>
                            </div>
                        </div>
                    </div>
                    {isOnExpedition && (
                        <div className="mt-3 bg-blue-950/40 border border-blue-700/30 rounded-lg p-1.5 flex flex-col items-center">
                            <span className="text-[7px] font-black text-blue-400 uppercase tracking-widest animate-pulse">On Expedition</span>
                            <button 
                                onClick={handleRecall}
                                className="mt-1 w-full py-1 bg-red-900/60 hover:bg-red-800 text-white rounded text-[8px] font-black uppercase flex items-center justify-center gap-1 transition-all"
                            >
                                <Ban className="w-2.5 h-2.5" /> Force Recall
                            </button>
                        </div>
                    )}
                </div>
            </div>

            <div className="absolute inset-0 z-10 w-full h-full pointer-events-none flex items-end justify-center">
                <div className="relative w-full h-full flex items-end justify-center animate-in fade-in zoom-in-95 duration-700 ease-out">
                    <div className="relative h-[90dvh] max-h-[110dvh] flex items-end justify-center">
                    <AnimatedMercenary
                        mercenary={mercenary}
                        className="h-full w-auto filter drop-shadow-[0_0_100px_rgba(0,0,0,1)]"
                    />

                    <div className="absolute bottom-10 left-1/2 -translate-x-1/2 w-64 h-10 bg-black/60 blur-3xl rounded-full -z-10"></div>

                    {floatingHearts.map((heart) => (
                        <Heart
                        key={heart.id}
                        className="absolute animate-heart fill-pink-500 text-pink-400 drop-shadow-[0_0_8px_rgba(236,72,153,0.6)]"
                        style={{
                            left: `${heart.left}%`,
                            bottom: '30%',
                            width: heart.size,
                            height: heart.size,
                            animationDelay: `${heart.delay}s`,
                            '--wobble': `${(Math.random() - 0.5) * 40}px`,
                        } as React.CSSProperties}
                        />
                    ))}
                    </div>
                </div>
            </div>

            <div className="absolute bottom-0 w-full h-[35dvh] md:h-64 z-20 flex items-end justify-center pointer-events-none">
                <div className="w-full h-full bg-[#2a1e16] border-t-4 md:border-t-[8px] border-[#3e2723] shadow-[0_-40px_60px_rgba(0,0,0,0.85)] relative overflow-hidden">
                    <div className="absolute inset-0 opacity-20" style={{ backgroundImage: 'repeating-linear-gradient(45deg, transparent, transparent 10px, #000 10px, #000 12px)' }}></div>
                    <div className="absolute inset-0 bg-gradient-to-b from-black/40 to-transparent"></div>
                </div>
            </div>

            <div className="absolute bottom-6 md:bottom-12 left-1/2 -translate-x-1/2 w-[92vw] md:w-[85vw] max-w-5xl z-50 flex flex-col items-center gap-[10px] pb-[env(safe-area-inset-bottom)] pointer-events-none">
                <div className={`flex flex-col items-end gap-2 w-full px-4 py-2 pointer-events-auto transition-opacity duration-500 ${(pendingGiftItem || step !== 'IDLE') ? 'opacity-30 pointer-events-none grayscale' : 'opacity-100'}`}>
                    <div className="flex wrap items-center justify-end gap-1.5 md:gap-3 w-full">
                        <button 
                            onClick={handleTalk}
                            className="flex items-center gap-1.5 md:gap-2 px-3 md:px-6 py-2.5 md:py-3.5 bg-stone-900/85 hover:bg-stone-800 border border-stone-700 rounded-xl backdrop-blur-md transition-all shadow-xl group shrink-0"
                        >
                            <MessageSquare className="w-3 h-3 md:w-4 md:h-4 text-amber-500" />
                            <span className="font-black text-[9px] md:text-xs text-stone-200 uppercase tracking-widest">Talk</span>
                        </button>

                        <button 
                            onClick={() => { playClick(); setShowGiftMenu(true); }}
                            className="flex items-center gap-1.5 md:gap-2 px-3 md:px-6 py-2.5 md:py-3.5 bg-stone-900/85 hover:bg-stone-800 border border-stone-700 hover:border-pink-500 rounded-xl backdrop-blur-md transition-all shadow-xl group shrink-0"
                        >
                            <Gift className="w-3 h-3 md:w-4 md:h-4 text-pink-500" />
                            <span className="font-black text-[9px] md:text-xs text-stone-200 uppercase tracking-widest">Gift</span>
                        </button>

                        {isHired ? (
                            <button 
                                onClick={handleTerminateInit}
                                disabled={isOnExpedition}
                                className={`flex items-center gap-1.5 md:gap-2 px-3 md:px-6 py-2.5 md:py-3.5 border rounded-xl backdrop-blur-md transition-all shadow-xl group shrink-0 text-white ${isOnExpedition ? 'bg-stone-900 border-stone-800 text-stone-600 cursor-not-allowed opacity-50' : 'bg-red-950/60 hover:bg-red-900/80 border border-red-800'}`}
                            >
                                <UserMinus className="w-3 h-3 md:w-4 md:h-4" />
                                <span className="font-black text-[9px] md:text-xs uppercase tracking-widest">Terminate</span>
                            </button>
                        ) : (
                            <button 
                                onClick={handleRecruitInit}
                                disabled={!canAfford || !hasAffinity}
                                className={`flex items-center gap-1.5 md:gap-2 px-3 md:px-6 py-2.5 md:py-3.5 border rounded-xl backdrop-blur-md transition-all shadow-xl group shrink-0 ${
                                    (!canAfford || !hasAffinity) 
                                    ? 'bg-stone-950/80 border-stone-800 text-stone-600 grayscale cursor-not-allowed' 
                                    : 'bg-amber-900/65 hover:bg-amber-800 border-amber-500 text-white'
                                }`}
                            >
                                <UserPlus className="w-3 h-3 md:w-4 md:h-4" />
                                <div className="flex flex-col items-start leading-none">
                                    <span className="font-black text-[9px] md:text-xs uppercase tracking-widest">Recruit</span>
                                    {hasAffinity && <span className="text-[7px] md:text-[8px] font-mono opacity-70">{hiringCost}G</span>}
                                </div>
                            </button>
                        )}

                        <button 
                            onClick={handleShowDetail}
                            className={`flex items-center gap-1.5 md:gap-2 px-3 md:px-6 py-2.5 md:py-3.5 bg-stone-900/85 hover:bg-stone-800 border border-stone-700 rounded-xl backdrop-blur-md transition-all shadow-xl group shrink-0 relative ${isHired ? 'hover:border-emerald-500' : 'hover:border-blue-500'}`}
                        >
                            {isHired ? <Wrench className="w-3 h-3 md:w-4 md:h-4 text-emerald-500" /> : <Search className="w-3 h-3 md:w-4 md:h-4 text-blue-500" />}
                            <span className="font-black text-[9px] md:text-xs text-stone-200 uppercase tracking-widest">
                                {isHired ? 'Manage' : 'Inspect'}
                            </span>
                            {hasUnallocated && (
                                <div className="absolute -top-2 -left-1 bg-amber-500 text-stone-900 p-0.5 rounded-full shadow-[0_0_10px_rgba(245,158,11,0.6)] animate-bounce border border-stone-950 z-10">
                                    <ChevronUp className="w-2.5 h-2.5 font-black" />
                                </div>
                            )}
                        </button>
                    </div>
                </div>

                <DialogueBox 
                    speaker={mercenary.name}
                    text={dialogue}
                    options={
                        pendingGiftItem ? [
                            { label: `Give ${pendingGiftItem.name}`, action: handleConfirmGift, variant: 'primary' },
                            { label: "Cancel", action: handleCancelGift, variant: 'neutral' }
                        ] : 
                        step === 'CONFIRM_HIRE' ? [
                            { label: `Sign Contract (-${hiringCost}G)`, action: handleConfirmHire, variant: 'primary' },
                            { label: "Think again", action: handleCancelStep, variant: 'neutral' }
                        ] : 
                        step === 'CONFIRM_FIRE' ? [
                            { label: "Terminate Contract", action: handleConfirmTerminate, variant: 'danger' },
                            { label: "Stay with me", action: handleCancelStep, variant: 'neutral' }
                        ] : []
                    }
                    className="w-full relative pointer-events-auto"
                />
            </div>

            {showGiftMenu && (
                <div className="fixed inset-0 z-[2000] flex items-center justify-center bg-black/80 backdrop-blur-sm animate-in fade-in duration-200 p-4">
