interface SettingsModalProps {
    isOpen: boolean;
    onClose: () => void;
    onQuit: () => void;
    onLoadRequest: (data: any, depth: number) => void;
}

const SettingsModal: React.FC<SettingsModalProps> = ({ isOpen, onClose, onQuit, onLoadRequest }) => {
    const { state, actions } = useGame();
    const [slModal, setSlModal] = useState<{ isOpen: boolean, mode: 'SAVE' | 'LOAD' }>({ isOpen: false, mode: 'SAVE' });
    const [loadConfirm, setLoadConfirm] = useState<{ isOpen: boolean, data: any, index: number | null }>({
        isOpen: false,
        data: null,
        index: null
    });

    const APP_VERSION = "0.1.42c";

    if (!isOpen) return null;

    const audio = state.settings.audio;

    const handleSlotAction = (slotIndex: number) => {
        if (slModal.mode === 'SAVE') {
            actions.saveGame(slotIndex);
        } else {
            const data = loadFromSlot(slotIndex);
            if (data) {
                if (data.version !== APP_VERSION) {
                    actions.showToast(`Load Failed: Version mismatch. (Save: v${data.version || '0.1.36'}, App: v${APP_VERSION})`);
                    return;
                }
                setLoadConfirm({ isOpen: true, data, index: slotIndex });
            }
        }
    };

    const handleConfirmLoad = () => {
        if (loadConfirm.data && loadConfirm.index !== null) {
            setLoadConfirm({ ...loadConfirm, isOpen: false });
            setSlModal({ ...slModal, isOpen: false });
            onClose();
            onLoadRequest(loadConfirm.data, loadConfirm.index);
        }
    };

    const toggleLogTicker = () => {
        playGlobalSfx('item_click.wav');
        actions.updateSettings({ showLogTicker: !state.settings.showLogTicker });
    };

    const toggleMasterAudio = () => {
        playGlobalSfx('item_click.wav');
        actions.updateSettings({
            audio: {
                ...audio,
                masterEnabled: !audio.masterEnabled
            }
        });
    };

    const updateVolume = (key: 'masterVolume' | 'musicVolume' | 'sfxVolume', value: number) => {
        if (!audio.masterEnabled) return;
        const enabledKey = key.replace('Volume', 'Enabled') as 'masterEnabled' | 'musicEnabled' | 'sfxEnabled';
        actions.updateSettings({
            audio: {
                ...audio,
                [key]: value,
                [enabledKey]: value > 0
            }
        });
    };

    const VolumeSlider = ({ label, value, icon: Icon, onChange, disabled }: { label: string, value: number, icon: any, onChange: (v: number) => void, disabled?: boolean }) => (
        <div className={`flex flex-col gap-1.5 p-3 rounded-xl border transition-all w-full ${disabled ? 'bg-stone-900/40 border-stone-800/50 opacity-40 grayscale' : 'bg-stone-800/40 border-stone-700/50'}`}>
            <div className="flex justify-between items-center">
                <div className="flex items-center gap-2">
                    <Icon className={`w-3.5 h-3.5 ${!disabled && value > 0 ? 'text-amber-500' : 'text-stone-600'}`} />
                    <span className="text-[9px] font-black text-stone-400 uppercase tracking-widest">{label}</span>
                </div>
                <span className="text-[9px] font-mono font-bold text-stone-500">{Math.round(value * 100)}%</span>
            </div>
            <input 
                type="range" min="0" max="1" step="0.01" 
                value={value} 
                disabled={disabled}
                onPointerDown={(e) => !disabled && e.stopPropagation()}
                onPointerMove={(e) => !disabled && e.stopPropagation()}
                onChange={(e) => !disabled && onChange(parseFloat(e.target.value))}
                onInput={(e) => !disabled && onChange(parseFloat((e.target as HTMLInputElement).value))}
                className={`w-full h-2.5 bg-stone-900 rounded-lg appearance-none cursor-pointer accent-amber-600 ${disabled ? 'cursor-not-allowed' : ''}`}
            />
        </div>
    );

    return (
        <>
            <div className="fixed inset-0 z-[1500] flex items-center justify-center bg-black/90 backdrop-blur-md px-[10%] py-[15%] animate-in fade-in duration-200 overflow-hidden">
                <div className="bg-stone-900 border-2 border-stone-700 rounded-3xl w-[90vw] max-w-[420px] h-fit max-h-full min-h-[200px] min-w-[280px] shadow-2xl flex flex-col overflow-hidden animate-in zoom-in-95 duration-200 mx-auto">

                    {/* Header */}
                    <div className="flex items-center justify-between p-5 border-b border-stone-800 bg-stone-850 shrink-0">
                        <div className="flex items-center gap-3">
                            <Settings className="w-6 h-6 text-amber-500 animate-spin-slow" />
                            <h3 className="font-bold font-serif uppercase tracking-widest text-base text-stone-100">System Menu</h3>
                        </div>
                        <SoundButton onClick={onClose} className="p-1.5 hover:bg-stone-800 rounded-full text-stone-500 transition-colors"><X className="w-6 h-6" /></SoundButton>
                    </div>

                    {/* Menu List */}
                    <div className="flex-1 p-5 space-y-6 overflow-y-auto custom-scrollbar">
                        {/* Persistence - Strictly 1 Column */}
                        <div className="space-y-2">
                            <h4 className="text-[9px] font-black text-stone-500 uppercase tracking-widest px-1">Persistence</h4>
                            <div className="flex flex-col gap-2.5">
                                <SoundButton
                                    onClick={() => setSlModal({ isOpen: true, mode: 'SAVE' })}
                                    className="w-full flex items-center gap-4 p-4 rounded-xl border border-stone-700 bg-stone-800 hover:border-amber-500 hover:bg-stone-750 text-stone-300 transition-all shadow-md"
                                >
                                    <Save className="w-5 h-5 text-amber-500" />
                                    <div className="flex flex-col items-start leading-none">
                                        <span className="font-black text-[11px] uppercase tracking-widest">Manual Save</span>
                                        <span className="text-[8px] text-stone-500 uppercase font-bold mt-1">Record current progress to a slot</span>
                                    </div>
                                </SoundButton>
                                <SoundButton
                                    onClick={() => setSlModal({ isOpen: true, mode: 'LOAD' })}
                                    className="w-full flex items-center gap-4 p-4 rounded-xl border border-stone-700 bg-stone-800 hover:border-stone-500 hover:bg-stone-750 text-stone-300 transition-all shadow-md"
                                >
                                    <Upload className="w-5 h-5 text-indigo-400" />
                                    <div className="flex flex-col items-start leading-none">
                                        <span className="font-black text-[11px] uppercase tracking-widest">Restore Data</span>
                                        <span className="text-[8px] text-stone-500 uppercase font-bold mt-1">Load previous session records</span>
                                    </div>
                                </SoundButton>
                            </div>
                        </div>

                        {/* Audio Engine - Strictly 1 Column */}
                        <div className="space-y-3">
                            <div className="flex items-center justify-between px-1">
                                <h4 className="text-[9px] font-black text-stone-500 uppercase tracking-widest">Audio Engine</h4>
                                <div className="flex items-center gap-2 cursor-pointer" onClick={toggleMasterAudio}>
                                    <span className="text-[8px] font-black text-stone-600 uppercase">{audio.masterEnabled ? 'ENABLED' : 'MUTED'}</span>
                                    <div className={`w-8 h-4 rounded-full p-0.5 transition-all duration-300 ${audio.masterEnabled ? 'bg-amber-600' : 'bg-stone-800'}`}>
                                        <div className={`w-3 h-3 bg-white rounded-full transition-all duration-300 ${audio.masterEnabled ? 'translate-x-4' : 'translate-x-0'}`} />
                                    </div>
                                </div>
                            </div>

                            <div className="flex flex-col gap-2.5">
                                <VolumeSlider 
                                    label="Master Output" 
                                    value={audio.masterVolume} 
                                    disabled={!audio.masterEnabled}
                                    icon={audio.masterEnabled && audio.masterVolume > 0 ? Volume2 : VolumeX} 
                                    onChange={(v) => updateVolume('masterVolume', v)} 
                                />
                                <VolumeSlider 
                                    label="Music Tracks" 
                                    value={audio.musicVolume} 
                                    disabled={!audio.masterEnabled}
                                    icon={Music} 
                                    onChange={(v) => updateVolume('musicVolume', v)} 
                                />
                                <VolumeSlider 
                                    label="Sound Effects" 
                                    value={audio.sfxVolume} 
                                    disabled={!audio.masterEnabled}
                                    icon={Zap} 
                                    onChange={(v) => updateVolume('sfxVolume', v)} 
                                />
                            </div>
                        </div>

                        {/* Game Preferences */}
                        <div className="space-y-2">
                            <h4 className="text-[9px] font-black text-stone-500 uppercase tracking-widest px-1">Interface</h4>
                            <div className="bg-stone-800/60 border border-stone-700 rounded-xl p-4 flex items-center justify-between group cursor-pointer hover:border-stone-500 transition-all" onClick={toggleLogTicker}>
                                <div className="flex items-center gap-3">
                                    <Layout className="w-5 h-5 text-indigo-400" />
                                    <div className="flex flex-col">
                                        <span className="font-black text-xs uppercase tracking-widest text-stone-200">Header Logs</span>
                                        <span className="text-[9px] text-stone-500 uppercase font-bold">Show/Hide Log Ticker Row</span>
                                    </div>
                                </div>
                                <div className={`w-10 h-6 rounded-full p-1 transition-all duration-300 ${state.settings.showLogTicker ? 'bg-amber-600' : 'bg-stone-900 border border-stone-700'}`}>
                                    <div className={`w-4 h-4 bg-white rounded-full shadow-md transition-all duration-300 ${state.settings.showLogTicker ? 'translate-x-4' : 'translate-x-0'}`} />
                                </div>
                            </div>
                        </div>

                        {/* Exit */}
                        <div className="pt-2 pb-4">
                            <SoundButton
                                onClick={onQuit}
                                className="w-full flex items-center gap-4 p-4 rounded-xl border border-stone-700 bg-red-950/10 hover:border-red-500 hover:bg-red-950/20 text-red-400 transition-all"
                            >
                                <div className="text-red-500"><LogOut className="w-5 h-5" /></div>
                                <span className="font-black text-xs uppercase tracking-widest">Quit to Title</span>
                            </SoundButton>
                        </div>
                    </div>

                    {/* Footer */}
                    <div className="p-3 bg-stone-950 text-center border-t border-stone-800 shrink-0">
                        <span className="text-[10px] text-stone-600 font-mono uppercase tracking-[0.2em]">Build v{APP_VERSION}</span>
                    </div>
                </div>
            </div>

            <SaveLoadModal 
                isOpen={slModal.isOpen}
                mode={slModal.mode}
                onClose={() => setSlModal({ ...slModal, isOpen: false })}
                onAction={handleSlotAction}
            />

            <ConfirmationModal 
                isOpen={loadConfirm.isOpen}
                title="Overwrite Progress?"
                message="Loading this file will discard any unsaved progress in your current session. Do you wish to continue?"
                confirmLabel="Confirm Load"
                onConfirm={handleConfirmLoad}
                onCancel={() => setLoadConfirm({ ...loadConfirm, isOpen: false })}
            />
        </>
    );
};

export default SettingsModal;

import React, { useState, useEffect } from 'react';
import { Save, Upload, X, Trash2, Clock, Coins, Calendar, ChevronRight } from 'lucide-react';
import { getSaveMetadataList, SaveMetadata, deleteSlot } from '../../utils/saveSystem';
import ConfirmationModal from './ConfirmationModal';
import { SoundButton } from '../common/ui/SoundButton';
import { playGlobalSfx } from '../../utils';

interface SaveLoadModalProps {
    isOpen: boolean;
    mode: 'SAVE' | 'LOAD';
    onClose: () => void;
    onAction: (slotIndex: number) => void;
}

const SaveLoadModal: React.FC<SaveLoadModalProps> = ({ isOpen, mode, onClose, onAction }) => {
    const [metaList, setMetaList] = useState<SaveMetadata[]>([]);
    const [deleteConfirm, setDeleteConfirm] = useState<{ isOpen: boolean, index: number | null }>({
        isOpen: false,
        index: null
    });

    useEffect(() => {
        if (isOpen) {
            setMetaList(getSaveMetadataList());
        }
    }, [isOpen]);

    if (!isOpen) return null;

    const slots = [0, 1, 2]; // 3개의 슬롯 지원

    const formatDate = (ts: number) => {
        return new Intl.DateTimeFormat('ko-KR', {
            month: 'short', day: 'numeric', hour: '2-digit', minute: '2-digit'
        }).format(new Date(ts));
    };

    const requestDelete = (e: React.MouseEvent, index: number) => {
        e.stopPropagation();
        playGlobalSfx('item_click.wav');
        setDeleteConfirm({ isOpen: true, index });
    };

    const handleConfirmDelete = () => {
        if (deleteConfirm.index !== null) {
            deleteSlot(deleteConfirm.index);
            setMetaList(getSaveMetadataList());
            setDeleteConfirm({ isOpen: false, index: null });
        }
    };

    const handleSlotClick = (index: number) => {
        onAction(index);
        if (mode === 'SAVE') {
            setTimeout(() => setMetaList(getSaveMetadataList()), 100);
        }
    };

    return (
        <>
            <div className="fixed inset-0 z-[1500] flex items-center justify-center bg-black/80 backdrop-blur-md px-[10%] py-[15%] overflow-hidden animate-in fade-in duration-200">
                <div className="bg-stone-900 border-2 border-stone-700 rounded-3xl w-[92vw] max-w-[450px] h-fit max-h-full min-h-[300px] min-w-[280px] shadow-[0_40px_80px_-20px_rgba(0,0,0,0.9)] overflow-hidden flex flex-col animate-in zoom-in-95 duration-200 mx-auto">

                    {/* Header */}
                    <div className="p-4 border-b border-stone-800 bg-stone-850 flex justify-between items-center shrink-0">
                        <div className="flex items-center gap-3">
                            <div className="bg-stone-800 p-2 rounded-xl border border-stone-700 text-amber-500">
                                {mode === 'SAVE' ? <Save className="w-5 h-5" /> : <Upload className="w-5 h-5" />}
                            </div>
                            <h3 className="font-bold font-serif text-lg text-stone-200 tracking-wide uppercase">
                                {mode === 'SAVE' ? 'Save Game' : 'Load Game'}
                            </h3>
                        </div>
                        <SoundButton onClick={onClose} className="p-2 hover:bg-stone-800 rounded-full text-stone-500 hover:text-stone-300 transition-colors ml-4">
                            <X className="w-5 h-5" />
                        </SoundButton>
                    </div>

                    {/* Slot List */}
                    <div className="p-4 space-y-3 overflow-y-auto flex-1 custom-scrollbar min-h-0">
                        {slots.map(index => {
                            const meta = metaList.find(m => m.index === index);
                            return (
                                <SoundButton 
                                    key={index}
                                    onClick={() => (meta || mode === 'SAVE') && handleSlotClick(index)}
                                    disabled={!meta && mode === 'LOAD'}
                                    className={`group relative h-20 p-3 rounded-2xl border-2 transition-all flex flex-col justify-center gap-2 text-left ${
                                        meta 
                                        ? 'bg-stone-800 border-stone-700 hover:border-amber-500 hover:bg-stone-750' 
                                        : mode === 'SAVE' 
                                            ? 'bg-stone-900 border-stone-800 border-dashed hover:border-stone-600 text-stone-600'
                                            : 'bg-stone-950 border-stone-900 text-stone-600 opacity-60'
                                    }`}
                                >
                                    <div className="flex justify-between items-center w-full gap-4">
                                        <div className="flex items-center gap-2 min-w-0">
                                            <span className="font-black text-[10px] uppercase tracking-widest text-stone-500 group-hover:text-amber-500">Slot {index + 1}</span>
                                            {meta?.version && (
                                                <span className="px-1.5 py-0.5 bg-stone-950 rounded text-[7px] font-mono font-bold text-stone-600 border border-stone-800 group-hover:border-amber-900/50 group-hover:text-amber-700 transition-colors">
                                                    v{meta.version}
                                                </span>
                                            )}
                                        </div>
                                        {meta && (
                                            <div className="flex items-center gap-2 shrink-0">
                                                <div className="flex items-center gap-1 text-[9px] text-stone-500 font-mono">
                                                    <Clock className="w-2.5 h-2.5" /> {formatDate(meta.timestamp)}
                                                </div>
                                                <button onClick={(e) => requestDelete(e, index)} className="p-1 hover:text-red-500 transition-colors">
                                                    <Trash2 className="w-3.5 h-3.5" />
                                                </button>
                                            </div>
                                        )}
                                    </div>

                                    {meta ? (
                                        <div className="flex items-center justify-between w-full gap-4">
                                            <div className="flex items-center gap-4">
                                                <div className="flex items-center gap-1.5">
                                                    <Calendar className="w-3.5 h-3.5 text-stone-500" />
                                                    <span className="text-xs md:text-sm font-bold text-stone-200">Day {meta.day}</span>
                                                </div>
                                                <div className="flex items-center gap-1.5">
                                                    <Coins className="w-3.5 h-3.5 text-amber-500" />
                                                    <span className="text-xs md:text-sm font-bold text-amber-400 font-mono">{meta.gold}G</span>
                                                </div>
                                            </div>
                                            <ChevronRight className="w-5 h-5 text-stone-600 group-hover:text-amber-500 group-hover:translate-x-1 transition-all" />
                                        </div>
                                    ) : (
                                        <div className="w-full py-0.5">
                                            <div className="text-center text-[10px] font-black uppercase tracking-[0.2em] italic opacity-70">
                                                {mode === 'SAVE' ? 'Click to Record Progress' : 'Empty Data Slot'}
                                            </div>
                                        </div>
                                    )}
                                </SoundButton>
                            );
                        })}
                    </div>

                    <div className="p-3 bg-stone-950 text-center border-t border-stone-800 shrink-0">
                        <p className="text-[9px] md:text-[10px] text-stone-600 font-mono uppercase tracking-tighter">Your progress is kept in browser local storage.</p>
                    </div>
                </div>
            </div>

            <ConfirmationModal 
                isOpen={deleteConfirm.isOpen}
                title="Delete Save Data"
                message={`Are you sure you want to delete the data in Slot ${deleteConfirm.index !== null ? deleteConfirm.index + 1 : ''}? This action cannot be undone.`}
                confirmLabel="Delete Forever"
                onConfirm={handleConfirmDelete}
                onCancel={() => setDeleteConfirm({ isOpen: false, index: null })}
                isDanger={true}
            />
        </>
    );
};

export default SaveLoadModal;

import React from 'react';
import { AlertTriangle } from 'lucide-react';
import { UI_MODAL_LAYOUT } from '../../config/ui-config';
import { SoundButton } from '../common/ui/SoundButton';

interface ConfirmationModalProps {
    isOpen: boolean;
    title: string;
    message: string;
    confirmLabel?: string;
    cancelLabel?: string;
    onConfirm: () => void;
    onCancel: () => void;
    isDanger?: boolean;
}

const ConfirmationModal: React.FC<ConfirmationModalProps> = ({ 
    isOpen, 
    title, 
    message, 
    confirmLabel = "Confirm", 
    cancelLabel = "Cancel", 
    onConfirm, 
    onCancel,
    isDanger = false
}) => {
    if (!isOpen) return null;

    return (
        <div 
            className={`${UI_MODAL_LAYOUT.OVERLAY} ${UI_MODAL_LAYOUT.Z_INDEX.CONFIRM} animate-in fade-in duration-200`} 
            onClick={onCancel}
        >
            <div 
                className={`${UI_MODAL_LAYOUT.CONTAINER} border-stone-700 animate-in zoom-in-95 duration-200`}
                onClick={(e) => e.stopPropagation()}
            >
                {/* Header */}
                <div className="p-4 md:p-6 bg-stone-850 border-b border-stone-800 flex items-center gap-4 shrink-0">
                    <div className={`p-2 rounded-lg shrink-0 ${isDanger ? 'bg-red-950/40 text-red-500 border border-red-900/30' : 'bg-amber-900/30 text-amber-500 border border-amber-800/30'}`}>
                        <AlertTriangle className="w-5 h-5 md:w-6 md:h-6" />
                    </div>
                    <h3 className="text-base md:text-xl font-bold text-stone-100 font-serif uppercase tracking-tight truncate pr-4">{title}</h3>
                </div>

                {/* Body */}
                <div className="flex-1 p-5 md:p-8 overflow-y-auto custom-scrollbar">
                    <p className="text-stone-400 text-xs md:text-sm leading-relaxed text-center italic px-2">
                        {message}
                    </p>
                </div>

                {/* Footer - Vertical stack for mobile */}
                <div className="p-4 md:p-6 bg-stone-900 border-t border-stone-800 flex flex-col-reverse sm:flex-row gap-2 md:gap-3 shrink-0">
                    <SoundButton 
                        onClick={onCancel}
                        className="w-full sm:flex-1 py-2.5 md:py-3 rounded-xl text-[10px] md:text-xs font-black text-stone-500 hover:text-stone-200 bg-stone-800 hover:bg-stone-750 transition-all uppercase tracking-widest px-4"
                    >
                        {cancelLabel}
                    </SoundButton>
                    <SoundButton 
                        onClick={onConfirm}
                        className={`w-full sm:flex-[1.5] py-2.5 md:py-3 rounded-xl text-[10px] md:text-xs font-black transition-all border-b-4 uppercase tracking-widest px-6 ${
                            isDanger 
                            ? 'bg-red-700 hover:bg-red-600 text-white border-red-900' 
                            : 'bg-amber-600 hover:bg-amber-500 text-white border-amber-800'
                        }`}
                    >
                        {confirmLabel}
                    </SoundButton>
                </div>
            </div>
        </div>
    );
};

export default ConfirmationModal;
